def safe_api_execution(api_call, context):
    # Vex idempotency check
    idempotency_key = f"workflow-{context['workflow_id']}-{context['step']}"

    check = vex.check_idempotency(
        key=idempotency_key,
        action=api_call.__name__
    )

    if check.already_executed:
        return check.previous_result

    try:
        result = api_call(**context)
        vex.record_success(idempotency_key, result)
        return result
    except Exception as e:
        vex.trigger_rollback(idempotency_key)
        raise

