class VexPermissionGuard:
    def __init__(self, vex_client):
        self.vex = vex_client

    def check_permissions(self, agent_role, api_endpoint, action):
        permissions = self.vex.validate_permissions(
            principal=f"agent:{agent_role}",
            resource=api_endpoint,
            action=action
        )

        if not permissions.granted:
            raise PermissionError(f"Access denied: {permissions.reason}")

# Integrate with CrewAI tools
def secure_tool_call(tool_func):
    @wraps(tool_func)
    def wrapper(self, *args, **kwargs):
        guard = VexPermissionGuard(vex)
        guard.check_permissions(
            self.role, 
            tool_func.__name__, 
            "execute"
        )
        return tool_func(self, *args, **kwargs)
    return wrapper

class WorkflowRollbackManager:
    def __init__(self, vex_client):
        self.vex = vex_client
        self.execution_log = []

    def log_step(self, step_id, action, state):
        self.execution_log.append({
            'step': step_id,
            'action': action,
            'state': state
        })

    def rollback(self, failed_step):
        # Rollback in reverse execution order
        for step in reversed(self.execution_log):
            if step['step'] >= failed_step:
                self.vex.execute_rollback(
                    workflow_id=step['action'],
                    step_id=step['step'],
                    state=step['state']
                )
                print(f"Rolled back step: {step['step']}")

# Global rollback manager
rollback_mgr = WorkflowRollbackManager(vex)

# Attach to crew execution
crew = Crew(
    agents=[coordinator, api_agent],
    verbose=2,
    callbacks=[rollback_mgr.log_step]
)
